.nav-list {
  flex-flow: row;
  justify-content: center;
  align-items: flex-end;
  margin-bottom: 0;
  padding-left: 0;
  display: flex;
  font-size: 1.4vw;
}

.nav-item {
  justify-content: center;
  align-items: center;
  width: 5em;
  transition: width .5s cubic-bezier(.16, 1, .3, 1);
  display: flex;
  position: relative;
}

.nav-item__link {
  z-index: 1;
  pointer-events: auto;
  justify-content: center;
  align-items: center;
  width: 100%;
  height: 100%;
  padding-left: .5em;
  padding-right: .5em;
  display: flex;
  position: relative;
}

.image {
  object-fit: contain;
  width: 100%;
}

.nav-item__tooltip {
  z-index: 0;
  background-color: var(--color-neutral-100);
  opacity: 0;
  white-space: nowrap;
  border-radius: .25em;
  padding: .4em .5em;
  font-size: 1em;
  transition: transform .5s cubic-bezier(.16, 1, .3, 1), opacity .5s cubic-bezier(.16, 1, .3, 1);
  position: absolute;
  top: 0;
  transform: translate(0, -80%);
  font-weight: 400;
}

.nav-item.sibling-far {
  width: 6em;
}

.nav-item.sibling-close {
  width: 7em;
}

.nav-item.hover {
  width: 8em;
}

.nav-item:hover .nav-item__tooltip{
  opacity: 1;
  transform:translate(0px, -140%);
}

Step 2: Add custom Javascript

function initAppleDockNavigationBar() {  
  // Select all .nav-item elements
  const navItems = document.querySelectorAll('.nav-item');

  // Helper function to add/remove a class to a sibling at a given offset
  const toggleSiblingClass = (items, index, offset, className, add) => {
    const sibling = items[index + offset];
    if (sibling) {
      sibling.classList.toggle(className, add);
    }
  };

  // Event listeners to toggle classes on hover
  navItems.forEach((item, index) => {
    item.addEventListener('mouseenter', () => {
      item.classList.add('hover'); // Add .hover to current item

      // Toggle classes for siblings
      toggleSiblingClass(navItems, index, -1, 'sibling-close', true); // Previous sibling
      toggleSiblingClass(navItems, index, 1, 'sibling-close', true);  // Next sibling
      toggleSiblingClass(navItems, index, -2, 'sibling-far', true);   // Previous-previous sibling
      toggleSiblingClass(navItems, index, 2, 'sibling-far', true);    // Next-next sibling
    });

    item.addEventListener('mouseleave', () => {
      item.classList.remove('hover'); // Remove .hover from current item

      // Toggle classes for siblings
      toggleSiblingClass(navItems, index, -1, 'sibling-close', false); // Previous sibling
      toggleSiblingClass(navItems, index, 1, 'sibling-close', false);  // Next sibling
      toggleSiblingClass(navItems, index, -2, 'sibling-far', false);   // Previous-previous sibling
      toggleSiblingClass(navItems, index, 2, 'sibling-far', false);    // Next-next sibling
    });
  });
}

// Initialize Apple Dock Navigation Bar
document.addEventListener('DOMContentLoaded', () => {
  initAppleDockNavigationBar();
});

Implementation

Wrapper
Use .nav-bar as the main container. It holds all .nav-item elements and controls their spacing and alignment.

Item
Each .nav-item contains an icon or some image, and an optional tooltip.
The hover animation enlarges the current item and also slightly scales the two closest neighbors using class logic controlled by the script.

Sibling classes
The animation uses helper classes to control sizing:
- .hover is applied to the active item.
- .sibling-close enlarges the items immediately next to the hovered one.
- .sibling-far slightly enlarges the second items away.
All classes are removed on mouseleave to reset the layout.

Tooltip
Each item can include a .nav-item__tooltip element that fades in above the icon when hovered.
Positioning and opacity are handled via CSS transitions.

Customization
You can change the overall growth intensity by adjusting the width values in CSS. Increase or decrease these values to make the effect subtler or more exaggerated:
.nav-item.sibling-far { width: 6em; }
.nav-item.sibling-close { width: 7em; }
.nav-item.hover { width: 8em; }
